import { Component, Event, EventEmitter, Prop, h } from '@stencil/core';
import type { FiscalDocuments } from '@/services/city-ledger/types';
import { invoiceIdRequiredFieldSchema, type CityLedgerTransactionFormDraft } from '../../ir-city-ledger-transaction-form.schema';

@Component({
  tag: 'ir-cl-debit-note-fields',
  styleUrl: 'ir-cl-debit-note-fields.css',
  scoped: true,
})
export class IrClDebitNoteFields {
  @Prop() invoiceId: string | undefined;
  @Prop() fiscalDocuments: FiscalDocuments = [];

  @Event() fieldChange: EventEmitter<Partial<CityLedgerTransactionFormDraft>>;

  render() {
    if (this.fiscalDocuments.length === 0) {
      return (
        <wa-callout size="small" variant="warning">
          <wa-icon slot="icon" name="triangle-exclamation"></wa-icon>
          No paid invoices are available. A debit note requires at least one paid invoice to reference. Please issue an invoice first, then return to create the debit note.
        </wa-callout>
      );
    }

    return (
      <div class="field">
        <ir-validator schema={invoiceIdRequiredFieldSchema} value={this.invoiceId ?? ''} valueEvent="change">
          <wa-select
            label="Invoice"
            size="small"
            required
            value={this.invoiceId ?? ''}
            onchange={event => {
              this.fieldChange.emit({ invoiceId: (event.target as HTMLSelectElement).value || undefined });
            }}
          >
            <wa-option value="">Select invoice</wa-option>
            {this.fiscalDocuments.map(doc => (
              <wa-option key={doc.FD_ID} value={String(doc.FD_ID)}>
                {doc.DOC_NUMBER} — {doc.FD_TYPE_NAME}
              </wa-option>
            ))}
          </wa-select>
        </ir-validator>
      </div>
    );
  }
}
